import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Read the entire line

        char[] buffer = new char[10]; // Creating a buffer of fixed size

        // Copying user input into the buffer with length check
        int lengthToCopy = Math.min(input.length(), buffer.length); // Limit to buffer size
        input.getChars(0, lengthToCopy, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
